(75,'customer_service','cs_reply_templates','[{\"category\":\"通用\",\"templates\":[{\"title\":\"欢迎语\",\"content\":\"您好，有什么可以帮助您的吗？\"},{\"title\":\"请稍等\",\"content\":\"请稍等，我为您查询一下，请不要离开。\"},{\"title\":\"感谢反馈\",\"content\":\"感谢您的反馈，我们会尽快处理您的问题。\"},{\"title\":\"祝福语\",\"content\":\"祝您使用愉快！如有其他问题，随时联系我们。\"}]},{\"category\":\"资产\",\"templates\":[{\"title\":\"余额查询结果\",\"content\":\"已为您查询余额，请在右侧面板查看详细资产信息。\"},{\"title\":\"冻结说明\",\"content\":\"您的资产处于冻结状态，这是因为有进行中的交易订单，交易完成后会自动解冻。\"},{\"title\":\"退款进度\",\"content\":\"退款已在处理中，预计在交易取消后立即返还到您的账户。\"}]},{\"category\":\"交易\",\"templates\":[{\"title\":\"订单状态说明\",\"content\":\"您的交易订单正在处理中，系统会自动完成撮合。如长时间未完成，可联系客服处理。\"},{\"title\":\"纠纷处理流程\",\"content\":\"我们已收到您的交易纠纷反馈，将在24小时内为您核实处理，期间请勿重复提交。\"},{\"title\":\"取消订单指引\",\"content\":\"如需取消订单，请在\\\"我的交易\\\"中找到对应订单点击取消。如遇问题可联系客服。\"}]},{\"category\":\"抽奖\",\"templates\":[{\"title\":\"概率机制说明\",\"content\":\"每次抽奖都会从奖品池中随机选取一个奖品，奖品价值由档位（高/中/低）决定。\"},{\"title\":\"保底规则说明\",\"content\":\"系统设有保底机制，连续多次低档位后会触发保底，保证获得中档或高档奖品。\"},{\"title\":\"记录查询结果\",\"content\":\"已为您查询抽奖记录，请在右侧面板的\\\"抽奖\\\"标签页查看详情。\"}]},{\"category\":\"物品\",\"templates\":[{\"title\":\"锁定原因说明\",\"content\":\"您的物品被锁定是因为有进行中的交易或兑换操作，操作完成后会自动解锁。\"},{\"title\":\"解锁操作指引\",\"content\":\"如物品长时间处于锁定状态，可能是操作异常。请提供物品名称，我为您核实处理。\"},{\"title\":\"物品使用说明\",\"content\":\"获得的物品可在背包中查看，部分物品可以在市场交易或用于兑换实物奖品。\"}]},{\"category\":\"SOP标准流程\",\"templates\":[{\"title\":\"交易超时标准处理\",\"content\":\"已检测到您有超时未完成的交易订单，我现在为您处理。超时订单将被取消并退还相应资产。\"},{\"title\":\"抽奖异常标准处理\",\"content\":\"经系统检查，您的抽奖记录显示正常。如仍有疑问，请提供具体的抽奖时间，我为您详细核实。\"},{\"title\":\"资产冻结标准处理\",\"content\":\"经核实您的冻结资产与交易订单有关，我现在为您解冻并退还。请稍等片刻。\"}]}]','json','客服快捷回复模板（JSON 数组，预设常用回复内容供客服选择）',1,0,NULL,'2026-03-21 06:13:05','2026-04-22 10:55:42'),
